import type { InputStream } from '@lezer/lr';

import { characterCodes } from '../character-codes.js';

const { BACKSLASH } = characterCodes;

/**
 * Try to match the given pattern in an input stream.
 * The given character sequence can be a single sequence or an array of sequences.
 * If one of those matches, the returned value is `true`.
 * @see dev-decisions.md for more details.
 * @internal
 */
export function matchCharacterSequence({
  inputStream,
  characterSequence: _characterSequence,
  offset = 0,
  leading: _leading = '',
  trailing: _trailing = '',
}: {
  /** The input stream currently being parsed. */
  inputStream: InputStream;
  /** The input string to look for in the stream. */
  characterSequence: string | string[];
  /** Match the given pattern starting from an offset. */
  offset?: number;
  /** Use the leading prop to check for matching input before the character sequence. */
  leading?: string | string[];
  /** Use the leading prop to check for matching input after the character sequence. */
  trailing?: string | string[];
}): boolean {
  const characterSequence = Array.isArray(_characterSequence)
    ? _characterSequence
    : [_characterSequence];
  const leading = Array.isArray(_leading)
    ? _leading
    : [_leading].filter(Boolean);

  // If the first character of the sequence is escaped by a backslash, the sequence doesn't match.
  if (inputStream.peek(offset - 1) === BACKSLASH) {
    return false;
  }

  const leadingSequenceMatches =
    leading.length > 0
      ? leading.some((sequence) =>
          sequence
            .split('')
            .reverse()
            .every(
              (character, index) =>
                String.fromCharCode(inputStream.peek(offset - index - 1)) ===
                character,
            ),
        )
      : true;

  const trailing = Array.isArray(_trailing)
    ? _trailing
    : [_trailing].filter(Boolean);

  // A keyword must be followed by a space. Else, it is just the start of another word.
  return characterSequence.some((sequence) => {
    const sequenceMatches = sequence
      .split('')
      .every(
        (character, index) =>
          String.fromCharCode(
            inputStream.peek(offset + index),
          ).toLowerCase() === character,
      );

    const trailingSequenceMatches =
      trailing.length > 0
        ? trailing.some((trailingSequence) =>
            trailingSequence
              .split('')
              .every(
                (character, index) =>
                  String.fromCharCode(
                    inputStream.peek(offset + sequence.length + index),
                  ) === character,
              ),
          )
        : true;

    return sequenceMatches && leadingSequenceMatches && trailingSequenceMatches;
  });
}
